-- 3. Views

-- View: answer_view
CREATE OR REPLACE VIEW `answer_view` AS select `user_has_assignment`.`id` AS `id`,`user_has_assignment`.`assignment_id` AS `assignment_id`,`assignment`.`assignment_name` AS `assignment_name`,`subject`.`name` AS `subject_name`,`user`.`id` AS `user_id`,`user`.`name` AS `user_name`,`user`.`email` AS `email`,`user_has_assignment`.`upload` AS `upload`,`user_has_assignment`.`marks` AS `marks`,`assignment_status`.`status` AS `marks_state`,`grade`.`name` AS `year` from (((((`user_has_assignment` left join `user` on((`user_has_assignment`.`user_id` = `user`.`id`))) left join `grade` on((`user_has_assignment`.`grade_id` = `grade`.`id`))) left join `assignment` on((`user_has_assignment`.`assignment_id` = `assignment`.`id`))) left join `subject` on((`assignment`.`subject_id` = `subject`.`id`))) left join `assignment_status` on((`assignment`.`assignment_status_id` = `assignment_status`.`id`)));

-- View: assignment_view
CREATE OR REPLACE VIEW `assignment_view` AS select `assignment`.`id` AS `id`,`user`.`name` AS `teacher`,`user`.`email` AS `email`,`grade`.`name` AS `year`,`subject`.`name` AS `subject_name`,`assignment`.`assignment_name` AS `assignment_name`,`assignment`.`file` AS `file`,`assignment`.`start_date` AS `start_date`,`assignment`.`end_date` AS `end_date`,`assignment_status`.`status` AS `status`,`assignment_status`.`id` AS `status_id` from ((((`assignment` left join `user` on((`assignment`.`teacher_id` = `user`.`id`))) left join `grade` on((`assignment`.`grade_id` = `grade`.`id`))) left join `subject` on((`assignment`.`subject_id` = `subject`.`id`))) left join `assignment_status` on((`assignment`.`assignment_status_id` = `assignment_status`.`id`)));

-- View: student_view
CREATE OR REPLACE VIEW `student_view` AS select `user`.`id` AS `id`,`user`.`name` AS `name`,`user`.`email` AS `email`,`user`.`user_type_id` AS `user_type_id`,`user`.`user_status_id` AS `user_status_id`,`grade`.`name` AS `year` from ((`user_has_grade` left join `user` on((`user_has_grade`.`user_id` = `user`.`id`))) left join `grade` on((`user_has_grade`.`grade_id` = `grade`.`id`))) where ((`user`.`user_type_id` = '4') and (`user`.`user_status_id` = '2'));

-- View: teacher_class
CREATE OR REPLACE VIEW `teacher_class` AS select `teacher_area`.`id` AS `id`,`teacher_area`.`teacher_id` AS `teacher_id`,`teacher_area`.`subject_id` AS `subject_id`,`subject`.`name` AS `subject_name`,`teacher_area`.`grade_id` AS `grade_id`,`grade`.`name` AS `year` from ((`teacher_area` left join `grade` on((`teacher_area`.`grade_id` = `grade`.`id`))) left join `subject` on((`teacher_area`.`subject_id` = `subject`.`id`)));

-- View: teacher_lesson
CREATE OR REPLACE VIEW `teacher_lesson` AS select `lesson`.`id` AS `id`,`user`.`name` AS `teacher`,`user`.`email` AS `email`,`subject`.`name` AS `subject_name`,`lesson`.`lesson_name` AS `lesson_name`,`lesson`.`lesson_date` AS `lesson_date`,`grade`.`id` AS `grade_id`,`grade`.`name` AS `year`,`lesson`.`upload` AS `upload` from (((`lesson` left join `grade` on((`lesson`.`grade_id` = `grade`.`id`))) left join `subject` on((`lesson`.`subject_id` = `subject`.`id`))) left join `user` on((`lesson`.`teacher_id` = `user`.`id`)));

-- View: user_view
CREATE OR REPLACE VIEW `user_view` AS select `user`.`id` AS `id`,`user`.`name` AS `name`,`user`.`mobile` AS `mobile`,`user`.`email` AS `email`,`user`.`user_type_id` AS `user_type_id`,`user_type`.`type` AS `type`,`user`.`user_status_id` AS `user_status_id`,`user_status`.`status` AS `status` from ((`user` left join `user_type` on((`user`.`user_type_id` = `user_type`.`id`))) left join `user_status` on((`user`.`user_status_id` = `user_status`.`id`)));

